# Category: datastore_security

from elasticsearch import Elasticsearch
from flask import Flask, request

app = Flask(__name__)

# Connect to Elasticsearch
es = Elasticsearch()

@app.route('/execute_script', methods=['POST'])
def execute_script():
    # Get script code from request
    script_code = request.json['script']

    # Execute script using Elasticsearch Script API
    response = es.search(
        index='your_index',
        body={
            'aggs': {
                'script_agg': {
                    'script': {
                        'inline': script_code
                    }
                }
            }
        }
    )

    # Return the response
    return response

if __name__ == '__main__':
    app.run(debug=True)